{"content":"import React, { useState } from 'react';
import { User } from '../types';
import { User as UserIcon, Mail, Shield, CreditCard, Key, Bell, LogOut, Fuel, Zap, Star, Check, Copy, AlertTriangle, Droplet, Database } from 'lucide-react';

interface AccountProps {
  user: User | null;
  onLogout: () => void;
  onNavigate: (view: any) => void;
}

const Account: React.FC<AccountProps> = ({ user, onLogout, onNavigate }) => {
  const [apiKeyCopied, setApiKeyCopied] = useState(false);
  const [activeTab, setActiveTab] = useState<'profile' | 'security' | 'billing'>('profile');

  if (!user) return null;

  const handleCopyApiKey = () => {
    navigator.clipboard.writeText(`cb_${user.id}_${Math.random().toString(36).substr(2, 9)}`);
    setApiKeyCopied(true);
    setTimeout(() => setApiKeyCopied(false), 2000);
  };

  // Helper pour mapper le plan technique aux noms marketing GTO Gas
  const getPlanDetails = (plan: string) => {
    switch (plan) {
      case 'enterprise':
        return { 
          name: 'La Citerne', 
          icon: <Database size={14} className="fill-current" />, 
          style: 'bg-purple-500/10 text-purple-500 border-white/[0.1] shadow-[0_0_15px_rgba(168,85,247,0.1)]' 
        };
      case 'pro':
        return { 
          name: 'La Pompe', 
          icon: <Fuel size={14} className="fill-current" />, 
          style: 'bg-purple-500/10 text-purple-400 border-primary/20 shadow-[0_0_15px_rgba(16,185,129,0.1)]' 
        };
      default:
        return { 
          name: 'Le Jerrican', 
          icon: <Droplet size={14} />, 
          style: 'bg-white/[0.04] text-gray-300 border-white/[0.08]' 
        };
    }
  };

  const planDetails = getPlanDetails(user.plan);

  return (
    <div className="max-w-5xl mx-auto px-4 py-10 animate-in fade-in duration-500">

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
        <div>
          <h1 className="text-3xl font-sans font-bold text-white mb-2">Mon Compte</h1>
          <p className="text-gray-500">Gérez vos informations personnelles, votre abonnement et vos préférences.</p>
        </div>
        <button 
          onClick={onLogout}
          className="flex items-center gap-2 px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-full transition-colors text-sm font-medium"
        >
          <LogOut size={16} /> Déconnexion
        </button>
      </div>

      <div className="grid lg:grid-cols-3 gap-8">

        {/* Left Column: Profile Card & Navigation */}
        <div className="space-y-6">
           {/* Profile Summary */}
           <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] text-center relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-24 bg-gradient-to-b from-white/5 to-transparent"></div>
              <div className="relative">
                <div className="w-24 h-24 mx-auto bg-gradient-to-br from-primary to-secondary rounded-full flex items-center justify-center text-white font-sans font-bold text-4xl shadow-xl shadow-primary/20 mb-4 border-4 border-[#000000]">
                    {user.name.charAt(0).toUpperCase()}
                </div>
                <h2 className="text-xl font-bold text-white">{user.name}</h2>
                <p className="text-sm text-gray-500 mb-4">{user.email}</p>

                {/* GTO Gas Plan Badge */}
                <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full border text-xs font-bold uppercase tracking-wide transition-all ${planDetails.style}`}>
                    {planDetails.icon}
                    {planDetails.name}
                </div>
              </div>
           </div>

           {/* GTO Gas Balance Card */}
           <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] bg-gradient-to-br from-accent/5 to-transparent relative overflow-hidden">
              <div className="flex justify-between items-start mb-4">
                  <div className="p-3 bg-accent/10 rounded-2xl text-accent">
                      <Fuel size={24} />
                  </div>
                  <button 
                    onClick={() => onNavigate('recharge')}
                    className="text-xs bg-accent text-white font-bold px-3 py-1.5 rounded-full hover:bg-purple-400 transition-colors"
                  >
                    Recharger
                  </button>
              </div>
              <p className="text-sm text-gray-500 mb-1">Solde GTO Gas</p>
              <div className="text-4xl font-sans font-bold text-white mb-2">{user.credits}</div>
              <div className="w-full bg-white/[0.08] h-1.5 rounded-full overflow-hidden">
                  <div className="bg-accent h-full rounded-full" style={{ width: `${Math.min((user.credits / 500) * 100, 100)}%` }}></div>
              </div>
              <p className="text-xs text-gray-500 mt-2">Suffisant pour ~{Math.floor(user.credits / 10)} audits standards</p>
           </div>
        </div>

        {/* Right Column: Details & Settings */}
        <div className="lg:col-span-2 space-y-8">

            {/* API Access */}
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
                <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                    <Key size={20} className="text-purple-400" /> Clés API & Intégrations
                </h3>
                <div className="bg-black/40 border border-white/[0.08] rounded-2xl p-4 flex items-center justify-between gap-4">
                    <div className="flex-1 overflow-hidden">
                        <p className="text-xs text-gray-500 mb-1 uppercase tracking-wider">Clé Publique</p>
                        <code className="text-sm text-purple-300 font-mono block truncate">cb_pk_live_{user.id.substring(0,8)}...</code>
                    </div>
                    <button 
                        onClick={handleCopyApiKey}
                        className="p-2 hover:bg-purple-500/10 rounded-full transition-colors text-gray-500 hover:text-white"
                        title="Copier la clé"
                    >
                        {apiKeyCopied ? <Check size={18} className="text-purple-400" /> : <Copy size={18} />}
                    </button>
                </div>
                <p className="text-xs text-gray-500 mt-3">
                    Cette clé permet d'utiliser l'API CitedBy.ai pour automatiser vos audits. Ne la partagez jamais.
                </p>
            </div>

            {/* General Settings Form */}
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
                <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                    <UserIcon size={20} className="text-blue-400" /> Informations Personnelles
                </h3>
                <div className="grid md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-500">Nom Complet</label>
                        <input 
                            type="text" 
                            defaultValue={user.name} 
                            className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white focus:border-purple-500/50 outline-none"
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-500">Email</label>
                        <input 
                            type="email" 
                            defaultValue={user.email} 
                            disabled
                            className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-gray-500 cursor-not-allowed"
                        />
                    </div>
                    <div className="space-y-2 md:col-span-2">
                        <label className="text-sm font-medium text-gray-500">Workspace / Entreprise</label>
                        <input 
                            type="text" 
                            defaultValue="Mon Espace Personnel" 
                            className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white focus:border-purple-500/50 outline-none"
                        />
                    </div>
                </div>
                <div className="mt-6 flex justify-end">
                    <button className="btn-gradient px-6 py-2.5 text-white font-bold text-sm">
                        Enregistrer les modifications
                    </button>
                </div>
            </div>

            {/* Notifications */}
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
                <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                    <Bell size={20} className="text-purple-400" /> Préférences de notification
                </h3>
                <div className="space-y-4">
                    {[
                        { label: "Rapport d'audit terminé", desc: "Recevoir un email quand une analyse longue est finie.", default: true },
                        { label: "Alerte de baisse de score", desc: "Notification si le score AEO chute de plus de 10%.", default: true },
                        { label: "Offres & Nouveautés", desc: "Newsletters produit et mises à jour des algorithmes.", default: false },
                    ].map((pref, i) => (
                        <div key={i} className="flex items-start justify-between pb-4 border-b border-white/[0.06] last:border-0 last:pb-0">
                            <div>
                                <p className="text-sm font-medium text-white">{pref.label}</p>
                                <p className="text-xs text-gray-500 mt-0.5">{pref.desc}</p>
                            </div>
                            <label className="relative inline-flex items-center cursor-pointer">
                                <input type="checkbox" defaultChecked={pref.default} className="sr-only peer" />
                                <div className="w-11 h-6 bg-gray-700 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full rtl:peer-checked:after:-translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:start-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-primary"></div>
                            </label>
                        </div>
                    ))}
                </div>
            </div>

            {/* Danger Zone */}
            <div className="border border-red-500/20 rounded-2xl p-6 bg-red-500/5">
                <h3 className="text-sm font-bold text-red-400 flex items-center gap-2 mb-2">
                    <AlertTriangle size={16} /> Zone de danger
                </h3>
                <p className="text-xs text-gray-500 mb-4">
                    La suppression du compte est irréversible. Toutes vos données d'audit et votre solde GTO Gas seront perdus.
                </p>
                <button className="text-xs font-bold text-red-500 hover:text-red-400 border border-red-500/30 hover:bg-red-500/10 px-4 py-2 rounded-full transition-colors">
                    Supprimer mon compte
                </button>
            </div>

        </div>
      </div>
    </div>
  );
};

export default Account;
"}

{"content":"
import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { Check, Download, ArrowLeft, ShieldCheck, LayoutList, History, FileText, Zap, Database, Fuel, Droplet, CreditCard, Star, Loader2, Sparkles } from 'lucide-react';
import jsPDF from 'jspdf';

interface PlanProps {
  onBack: () => void;
  user: User | null;
  onUpgrade: (plan: 'free' | 'pro' | 'enterprise') => void;
  initialTab?: 'my-plan' | 'pricing' | 'billing';
}

const Plan: React.FC<PlanProps> = ({ onBack, user, onUpgrade, initialTab = 'my-plan' }) => {
  const [activeTab, setActiveTab] = useState<'my-plan' | 'pricing' | 'billing'>(initialTab);
  const [isProcessing, setIsProcessing] = useState(false);

  useEffect(() => {
    setActiveTab(initialTab);
  }, [initialTab]);

  // Mock Data pour l'historique
  const payments = [
    { id: 'INV-2024-003', date: '01/03/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
    { id: 'INV-2024-002', date: '01/02/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
    { id: 'INV-2024-001', date: '15/01/2024', amount: 49.00, desc: 'Pack GTO Gas (La Pompe)', status: 'Payé' },
  ];

  const plans = [
    {
      id: 'free',
      name: 'Starter',
      price: 0,
      period: '/mois',
      icon: <Droplet size={24} />,
      features: ['1 Projet Actif / mois', 'Audit manuel', 'Support communauté'],
      cta: 'Plan Actuel',
      current: user?.plan === 'free'
    },
    {
      id: 'pro',
      name: 'Pro',
      price: 89,
      period: '/mois',
      icon: <Fuel size={24} />,
      popular: true,
      features: ['Indexation IA', '3 Projets Actifs / mois', 'Monitoring Continu', 'Support Prioritaire', 'API Access (Beta)', 'Rapports PDF marque blanche'],
      cta: 'Passer Pro',
      current: user?.plan === 'pro'
    },
    {
      id: 'enterprise',
      name: 'Agency',
      price: 299,
      period: '/mois',
      icon: <Database size={24} />,
      features: ['Indexation IA', 'Projets illimités', 'Dedicated Account Manager', 'API Full Access', 'SSO & Sécurité avancée', 'Formation AEO équipe'],
      cta: 'Contacter Ventes',
      current: user?.plan === 'enterprise'
    }
  ];

  const handleUpgradeClick = (planId: string) => {
    if (planId === 'enterprise') {
        window.location.href = "mailto:sales@citedby.ai";
        return;
    }

    setIsProcessing(true);
    // Simulation API call
    setTimeout(() => {
        onUpgrade(planId as any);
        setIsProcessing(false);
        setActiveTab('my-plan');
        alert(`Félicitations ! Vous êtes passé au plan ${planId.toUpperCase()}.`);
    }, 1500);
  };

  const generateInvoice = (payment: typeof payments[0]) => {
    if (!user) return;
    const doc = new jsPDF();

    // Header
    doc.setFontSize(22);
    doc.setFont("helvetica", "bold");
    doc.text("CitedBy.ai", 20, 20);

    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    doc.text(`Facture N° ${payment.id}`, 20, 30);
    doc.text(`Date : ${payment.date}`, 20, 35);

    // Client Info
    doc.text("Facturé à :", 140, 30);
    doc.setFont("helvetica", "bold");
    doc.text(user.name || "Client", 140, 35);
    doc.setFont("helvetica", "normal");
    doc.text(user.email || "", 140, 40);

    // Line Items Header
    doc.line(20, 55, 190, 55);
    doc.setFont("helvetica", "bold");
    doc.text("Description", 20, 62);
    doc.text("Montant HT", 160, 62);
    doc.line(20, 66, 190, 66);

    // Item
    const priceHT = (payment.amount / 1.2).toFixed(2);
    const tva = (payment.amount - parseFloat(priceHT)).toFixed(2);

    doc.setFont("helvetica", "normal");
    doc.text(payment.desc, 20, 75);
    doc.text(`${priceHT} €`, 160, 75);

    // Totals
    doc.line(20, 90, 190, 90);
    doc.text("Sous-total HT :", 130, 100);
    doc.text(`${priceHT} €`, 160, 100);

    doc.text("TVA (20%) :", 130, 107);
    doc.text(`${tva} €`, 160, 107);

    doc.setFont("helvetica", "bold");
    doc.setFontSize(12);
    doc.text("Total TTC :", 130, 117);
    doc.text(`${payment.amount.toFixed(2)} €`, 160, 117);

    doc.setFontSize(8);
    doc.setFont("helvetica", "italic");
    doc.text("Merci de votre confiance. Paiement effectué par CB.", 20, 140);

    doc.save(`Facture_${payment.id}.pdf`);
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-10 animate-in fade-in duration-500 min-h-screen">
      <button onClick={onBack} className="flex items-center text-gray-500 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour
      </button>

      <div className="text-center mb-10">
         <h1 className="text-4xl font-sans font-bold text-white mb-4">Plan & Facturation</h1>
         <p className="text-gray-500 max-w-2xl mx-auto">Gérez vos informations personnelles, votre abonnement et vos préférences.</p>
      </div>

      {/* Tabs Navigation */}
      <div className="flex justify-center mb-12">
        <div className="inline-flex bg-white/[0.04] p-1.5 rounded-2xl border border-white/[0.08]">
          <button
            onClick={() => setActiveTab('my-plan')}
            className={`px-6 py-2.5 rounded-2xl text-sm font-bold transition-all flex items-center gap-2 ${
              activeTab === 'my-plan' ? 'bg-gradient-to-r from-purple-500 to-violet-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'
            }`}
          >
            <ShieldCheck size={16} /> Mon Abonnement
          </button>
          <button
            onClick={() => setActiveTab('pricing')}
            className={`px-6 py-2.5 rounded-2xl text-sm font-bold transition-all flex items-center gap-2 ${
              activeTab === 'pricing' ? 'bg-gradient-to-r from-purple-500 to-violet-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'
            }`}
          >
            <LayoutList size={16} /> Changer d'offre
          </button>
          <button
            onClick={() => setActiveTab('billing')}
            className={`px-6 py-2.5 rounded-2xl text-sm font-bold transition-all flex items-center gap-2 ${
              activeTab === 'billing' ? 'bg-gradient-to-r from-purple-500 to-violet-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'
            }`}
          >
            <History size={16} /> Historique & Factures
          </button>
        </div>
      </div>

      {/* TAB: MON ABONNEMENT */}
      {activeTab === 'my-plan' && (
        <div className="animate-in fade-in slide-in-from-left-4 duration-300 grid md:grid-cols-2 gap-8">
            {/* Current Plan Card */}
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08] relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-purple-500/10 blur-3xl -z-10"></div>

                <div className="flex justify-between items-start mb-8">
                    <div>
                        <p className="text-sm text-gray-500 uppercase tracking-wider mb-1">Plan Actuel</p>
                        <h3 className="text-3xl font-sans font-bold text-white capitalize">{user?.plan}</h3>
                        <div className="flex items-center gap-2 mt-2">
                            <span className="w-2 h-2 rounded-full bg-purple-400 animate-pulse"></span>
                            <span className="text-xs text-purple-300 font-bold">Actif • Renouvellement le 01/04/2024</span>
                        </div>
                    </div>
                    <div className="w-12 h-12 rounded-2xl bg-white/[0.04] flex items-center justify-center text-white">
                        {user?.plan === 'pro' ? <Fuel /> : user?.plan === 'enterprise' ? <Database /> : <Droplet />}
                    </div>
                </div>

                <div className="space-y-4 mb-8 bg-black/20 p-6 rounded-2xl border border-white/[0.06]">
                    <div>
                        <div className="flex justify-between items-end mb-2">
                            <span className="text-sm text-gray-500">Projets Actifs (Quota Mensuel)</span>
                            <span className="text-sm font-bold text-white">{user?.plan === 'free' ? '1 max' : user?.plan === 'pro' ? '3 max' : 'Illimité'}</span>
                        </div>
                        <div className="h-1.5 bg-gray-700 rounded-full overflow-hidden">
                            <div className="h-full bg-primary rounded-full" style={{ width: user?.plan === 'free' ? '100%' : '66%' }}></div>
                        </div>
                    </div>
                    <div>
                        <div className="flex justify-between items-end mb-2">
                            <span className="text-sm text-gray-500">Crédits GTO Gas</span>
                            <span className="text-sm font-bold text-white">{user?.credits} restants</span>
                        </div>
                        <div className="h-1.5 bg-gray-700 rounded-full overflow-hidden">
                            <div className="h-full bg-accent rounded-full" style={{ width: '40%' }}></div>
                        </div>
                    </div>
                </div>

                <div className="flex gap-4">
                    <button onClick={() => setActiveTab('pricing')} className="flex-1 py-3 bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors">
                        Mettre à niveau
                    </button>
                    <button className="px-4 py-3 bg-white/[0.04] text-gray-300 font-bold rounded-2xl hover:bg-purple-500/10 transition-colors border border-white/[0.08]">
                        Gérer Stripe
                    </button>
                </div>
            </div>

            {/* Billing Info */}
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08] flex flex-col justify-between">
                <div>
                    <h3 className="font-bold text-white mb-6 flex items-center gap-2">
                        <CreditCard size={20} className="text-gray-500" /> Moyen de paiement
                    </h3>
                    <div className="flex items-center gap-4 bg-white/[0.04] p-4 rounded-2xl border border-white/[0.06] mb-6">
                        <div className="w-10 h-6 bg-white rounded flex items-center justify-center">
                            <img src="https://upload.wikimedia.org/wikipedia/commons/2/2a/Mastercard-logo.svg" alt="Mastercard" className="h-4" />
                        </div>
                        <div>
                            <p className="text-sm font-bold text-white">•••• •••• •••• 4242</p>
                            <p className="text-xs text-gray-500">Expire le 12/25</p>
                        </div>
                        <button className="ml-auto text-xs text-purple-400 hover:underline">Modifier</button>
                    </div>

                    <h3 className="font-bold text-white mb-4">Adresse de facturation</h3>
                    <div className="text-sm text-gray-500 space-y-1">
                        <p>{user?.name}</p>
                        <p>123 Avenue de l'Innovation</p>
                        <p>75011 Paris, France</p>
                        <p className="mt-2 text-xs text-gray-500">TVA: FR 12 345 678 901</p>
                    </div>
                </div>

                <button className="text-sm text-gray-500 hover:text-white transition-colors text-left mt-6">
                    Mettre à jour les informations de facturation
                </button>
            </div>
        </div>
      )}

      {/* TAB: PRICING (UPSELL) */}
      {activeTab === 'pricing' && (
        <div className="animate-in fade-in slide-in-from-right-4 duration-300">
            <div className="grid md:grid-cols-3 gap-6">
                {plans.map((plan) => (
                    <div 
                        key={plan.id} 
                        className={`relative ninja-card rounded-2xl p-6 border flex flex-col transition-all ${
                            plan.popular
                                ? 'border-purple-500 bg-white/[0.04] shadow-[0_0_40px_rgba(168,85,247,0.15)] scale-105 z-10'
                                : 'border-white/[0.08] hover:border-white/20'
                        } ${plan.current ? 'opacity-75 grayscale-[0.5]' : ''}`}
                    >
                        {plan.popular && (
                            <div className="absolute -top-4 left-1/2 -translate-x-1/2 bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold text-xs px-4 py-1 rounded-full uppercase tracking-wider">
                                Recommandé
                            </div>
                        )}

                        <div className="mb-6 flex items-center justify-between">
                            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${plan.popular ? 'bg-purple-500/20 text-purple-400' : 'bg-white/[0.04] text-gray-500'}`}>
                                {plan.icon}
                            </div>
                            {plan.current && (
                                <span className="bg-purple-500/10 text-purple-300 text-xs px-2 py-1 rounded border border-white/[0.1]">Actuel</span>
                            )}
                        </div>

                        <h3 className="text-xl font-bold text-white mb-2">{plan.name}</h3>
                        <div className="flex items-baseline gap-1 mb-6">
                            <span className="text-3xl font-sans font-bold text-white">{plan.price}€</span>
                            <span className="text-sm text-gray-500">{plan.period}</span>
                        </div>

                        <ul className="space-y-3 mb-8 flex-1">
                            {plan.features.map((feat, i) => (
                                <li 
                                    key={i} 
                                    className={`flex items-start gap-3 text-sm ${
                                        feat === 'Indexation IA'
                                            ? 'text-white font-bold bg-white/[0.04] -mx-2 p-2 rounded-full'
                                            : 'text-gray-300'
                                    }`}
                                >
                                    {feat === 'Indexation IA' ? (
                                        <Sparkles size={16} className="mt-0.5 text-accent shrink-0 animate-pulse" />
                                    ) : (
                                        <Check size={16} className={`mt-0.5 ${plan.popular ? 'text-purple-400' : 'text-gray-500'} shrink-0`} />
                                    )}
                                    {feat}
                                </li>
                            ))}
                        </ul>

                        <button
                            onClick={() => handleUpgradeClick(plan.id)}
                            disabled={plan.current || isProcessing}
                            className={`w-full py-3 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all ${
                                plan.popular
                                    ? 'bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white shadow-lg shadow-purple-500/20'
                                    : 'bg-white/[0.08] hover:bg-purple-500/20 text-white hover:text-white border border-white/[0.08]'
                            } ${plan.current ? 'cursor-not-allowed opacity-50' : ''}`}
                        >
                            {isProcessing && !plan.current ? <Loader2 className="animate-spin" /> : plan.cta}
                        </button>
                    </div>
                ))}
            </div>
        </div>
      )}

      {/* TAB: FACTURATION */}
      {activeTab === 'billing' && (
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
            <div className="ninja-card rounded-2xl border border-white/[0.08] overflow-hidden">
                <div className="p-6 border-b border-white/[0.08] flex justify-between items-center bg-white/[0.04]">
                    <h3 className="font-bold text-white flex items-center gap-2">
                        <FileText size={20} className="text-gray-500" /> Historique des paiements
                    </h3>
                    <button className="text-xs bg-white/[0.04] hover:bg-purple-500/10 border border-white/[0.08] px-3 py-1.5 rounded-full text-gray-300 transition-colors">
                        Tout télécharger
                    </button>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead>
                            <tr className="bg-[#000000] text-xs text-gray-500 uppercase tracking-wider">
                                <th className="px-6 py-4 font-medium">Référence</th>
                                <th className="px-6 py-4 font-medium">Date</th>
                                <th className="px-6 py-4 font-medium">Description</th>
                                <th className="px-6 py-4 font-medium">Montant</th>
                                <th className="px-6 py-4 font-medium">Statut</th>
                                <th className="px-6 py-4 font-medium text-right">Facture</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5">
                            {payments.map((payment) => (
                                <tr key={payment.id} className="hover:bg-white/[0.02] transition-colors">
                                    <td className="px-6 py-4 text-sm font-medium text-white">{payment.id}</td>
                                    <td className="px-6 py-4 text-sm text-gray-500">{payment.date}</td>
                                    <td className="px-6 py-4 text-sm text-gray-300">{payment.desc}</td>
                                    <td className="px-6 py-4 text-sm font-bold text-white">{payment.amount.toFixed(2)} €</td>
                                    <td className="px-6 py-4">
                                        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-purple-500/10 text-purple-300 border border-white/[0.1]">
                                            <div className="w-1.5 h-1.5 rounded-full bg-purple-400"></div> Payé
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-right">
                                        <button 
                                            onClick={() => generateInvoice(payment)}
                                            className="text-gray-500 hover:text-purple-400 transition-colors p-2 hover:bg-white/[0.04] rounded-full" 
                                            title="Télécharger PDF"
                                        >
                                            <Download size={18} />
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>

                <div className="p-4 bg-white/[0.04] border-t border-white/[0.08] text-center">
                    <button className="text-xs text-gray-500 hover:text-white transition-colors">
                        Charger plus de factures...
                    </button>
                </div>
            </div>
        </div>
      )}

    </div>
  );
};

export default Plan;
"}

{"content":"import React, { useState, useMemo, useCallback, useEffect, lazy, Suspense } from 'react';
import { User, AnalysisResult, SMCContent, GeneratedSolution } from './types';
import { analyzeUrl } from './services/analyzer';
import { db } from './services/database';
import Home from './pages/Home';
import Login from './pages/Login';
import Analyze from './pages/Analyze';

// Lazy-loaded pages for bundle optimization
const Dashboard = lazy(() => import('./pages/Dashboard'));
const GenerativeTools = lazy(() => import('./pages/GenerativeTools'));
const Results = lazy(() => import('./pages/Results').then(m => ({ default: m.Results })));
const HistoryView = lazy(() => import('./pages/History'));
const SMCStudio = lazy(() => import('./pages/SMCStudio'));
const SourceOfTruth = lazy(() => import('./pages/SourceOfTruth'));
const SchemaOrg = lazy(() => import('./pages/SchemaOrg'));
const PublisherRequest = lazy(() => import('./pages/PublisherRequest'));
const RobotsTxt = lazy(() => import('./pages/RobotsTxt'));
const Directory = lazy(() => import('./pages/Directory'));
const DirectoryEntity = lazy(() => import('./pages/DirectoryEntity'));
const Recharge = lazy(() => import('./pages/Recharge'));
const Plan = lazy(() => import('./pages/Plan'));
const Projects = lazy(() => import('./pages/Projects'));
const Account = lazy(() => import('./pages/Account'));
const Clients = lazy(() => import('./pages/Clients'));
const Affiliation = lazy(() => import('./pages/Affiliation'));
const ContentWriter = lazy(() => import('./pages/ContentWriter'));
const Reputation = lazy(() => import('./pages/Reputation'));
const BotTracking = lazy(() => import('./pages/BotTracking'));
const Messages = lazy(() => import('./pages/Messages'));
const AlertsAEO = lazy(() => import('./pages/AlertsAEO'));
import {
  LogOut, Zap, Github, Twitter, Linkedin, Home as HomeIcon, LayoutDashboard,
  Globe, ScanLine, Menu, CreditCard, FolderOpen, FileText, FileCode, History,
  Fuel, User as UserIcon, PenTool, Code, ClipboardList, ChevronDown, ChevronRight,
  Archive, CheckSquare, Sparkles, Users, MessageSquare, Bell, ShoppingBag,
  Settings, Construction, BarChart3, Wrench, Share2, Feather, Shield, X
} from 'lucide-react';
import { I18nProvider, useTranslation, LanguageSelector } from './i18n';

const PLAN_LIMITS = {
  free: 1,
  pro: 3,
  enterprise: 1000 // Illimité en pratique
};

const App: React.FC = () => {
  return (
    <I18nProvider>
      <AppContent />
    </I18nProvider>
  );
};

const AppContent: React.FC = () => {
  const { t, tf, locale } = useTranslation();
  const [currentView, setCurrentView] = useState<'home' | 'analyze' | 'results' | 'directory' | 'directory-entity' | 'login' | 'projects' | 'source-of-truth' | 'robots-txt' | 'history' | 'recharge' | 'account' | 'plan' | 'publisher-request' | 'schema-org' | 'smc-studio' | 'dashboard' | 'generative-tools' | 'clients' | 'affiliation' | 'messages' | 'alerts' | 'content-writer' | 'reputation' | 'bot-tracking'>('home');
  const [viewHistory, setViewHistory] = useState<string[]>([]);
  const [refreshKey, setRefreshKey] = useState(0); // Used to force remount of components

  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
  const [history, setHistory] = useState<AnalysisResult[]>([]);

  // Load history from DB on mount
  useEffect(() => {
    const loadedHistory = db.getAll();
    setHistory(loadedHistory);
  }, []);

  // Bibliothèques de contenu généré
  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]); 
  const [truthLibrary, setTruthLibrary] = useState<SMCContent[]>([]);
  const [schemaLibrary, setSchemaLibrary] = useState<SMCContent[]>([]);
  const [robotsLibrary, setRobotsLibrary] = useState<SMCContent[]>([]);

  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [resultsTab, setResultsTab] = useState<'overview' | 'details' | 'archives' | 'recommendations'>('overview');
  const [publisherRequestData, setPublisherRequestData] = useState<{ topic: string, url: string, brief: string } | null>(null);
  const [initialRechargePackId, setInitialRechargePackId] = useState<number | null>(null);
  const [initialPlanTab, setInitialPlanTab] = useState<'my-plan' | 'pricing' | 'billing'>('my-plan');

  // État pour gérer l'ouverture des sections du menu (Accordion exclusif)
  const [sectionsState, setSectionsState] = useState({
    optimization: false,
    tools: false
  });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Default user is NULL to allow testing the login flow
  const [user, setUser] = useState<User | null>(null);

  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
  const monthlyProjectCount = useMemo(() => {
    if (history.length === 0) return 0;

    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
    const now = new Date();
    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);

    // 1. Identifier la date de création (première analyse) de chaque domaine
    const projectCreationDates = new Map<string, Date>();

    history.forEach(h => {
        let hostname;
        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }

        const analysisDate = new Date(h.timestamp);

        if (!projectCreationDates.has(hostname)) {
            projectCreationDates.set(hostname, analysisDate);
        } else {
            // On garde la date la plus ancienne trouvée pour ce domaine
            if (analysisDate < projectCreationDates.get(hostname)!) {
                projectCreationDates.set(hostname, analysisDate);
            }
        }
    });

    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
    let count = 0;
    projectCreationDates.forEach((creationDate) => {
        if (creationDate >= billingCycleStart) {
            count++;
        }
    });

    return count;
  }, [history]);

  const navigateTo = (view: typeof currentView) => {
    setIsMobileMenuOpen(false);
    // Si on navigue vers autre chose que recharge, on reset l'ID du pack
    if (view !== 'recharge') {
        setInitialRechargePackId(null);
    }
    // Reset l'onglet du plan si on ne va pas vers le plan
    if (view !== 'plan') {
        setInitialPlanTab('my-plan');
    }
    setViewHistory(prev => [...prev, currentView]);
    setCurrentView(view);
    setRefreshKey(prev => prev + 1); // Force remount to reset internal state of views
  };

  const goBack = () => {
    setIsMobileMenuOpen(false);
    if (viewHistory.length > 0) {
      const newHistory = [...viewHistory];
      const prevView = newHistory.pop();
      setViewHistory(newHistory);
      if (prevView) {
        setCurrentView(prevView as any);
        setRefreshKey(prev => prev + 1);
      }
    } else {
      setCurrentView('home'); // Default fallback
      setRefreshKey(prev => prev + 1);
    }
  };

  const toggleSection = (section: keyof typeof sectionsState) => {
    setSectionsState(prev => {
      const isAlreadyOpen = prev[section];
      return {
        optimization: false,
        tools: false,
        [section]: !isAlreadyOpen
      };
    });
  };

  const handleHomeClick = () => {
    navigateTo('home');
    setSectionsState({
      optimization: false,
      tools: false
    });
  };

  const handleDashboardClick = () => {
    navigateTo('dashboard');
    setSectionsState({
      optimization: false,
      tools: false
    });
  };

  const handleRechargeClick = () => {
    navigateTo('recharge');
    setSectionsState({
      optimization: false,
      tools: false
    });
  };

  const handleDirectRecharge = (packId: number) => {
    setInitialRechargePackId(packId);
    navigateTo('recharge');
  };

  const handleAnalyze = async (url: string) => {
    // Vérification de la limite de projets (Quota mensuel)
    if (user) {
        const limit = PLAN_LIMITS[user.plan] || 1;
        let hostname = url;
        try { hostname = new URL(url).hostname; } catch(e) {}

        // On vérifie si c'est un projet déjà existant dans l'historique global
        const isExistingProject = history.some(h => {
            try { return new URL(h.url).hostname === hostname; } 
            catch(e) { return false; }
        });

        // Si c'est un tout nouveau projet et qu'on a atteint la limite MENSUELLE
        // Les anciens projets ne comptent pas dans cette limite
        if (!isExistingProject && monthlyProjectCount >= limit) {
            // Redirection directe vers la page Plan
            alert(`Limite de nouveaux projets atteinte pour ce mois (${monthlyProjectCount}/${limit}). Passez au plan supérieur pour ajouter plus de projets.`);
            navigateTo('plan');
            return;
        }
    }

    setIsAnalyzing(true);
    try {
      const result = await analyzeUrl(url);
      setAnalysisData(result);

      // Update history via DB service
      const updatedHistory = db.add(result);
      setHistory(updatedHistory);

      // Redirection vers Monitoring AEO (Projects)
      navigateTo('projects');
      setSectionsState({
        optimization: false,
        tools: false
      });
    } catch (error) {
      console.error("Analysis failed", error);
      alert("Erreur lors de l'analyse. Veuillez réessayer.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // Used for Admin/User private analysis view
  const handleViewAnalysis = (result: AnalysisResult, tab: any = 'overview') => {
    setAnalysisData(result);
    setResultsTab(tab);
    // Redirect to Projects (Monitoring AEO) instead of Results (Report)
    navigateTo('projects');
    setSectionsState({
        optimization: true,
        tools: false
    });
  };

  // New handler for Public Directory View
  const handleViewDirectoryEntity = (result: AnalysisResult) => {
    setAnalysisData(result);
    navigateTo('directory-entity');
  };

  const handleSubMenuNavigation = (tab: 'overview' | 'details' | 'archives') => {
    if (analysisData) {
      setResultsTab(tab);
      navigateTo('results');
    } else if (history.length > 0) {
      handleViewAnalysis(history[0], tab);
    } else {
      alert("Veuillez d'abord lancer une analyse pour accéder au plan d'actions.");
      navigateTo('analyze');
    }
  };

  const handleUpdateAnalysis = (index: number, updatedData: Partial<AnalysisResult>) => {
    const updatedHistory = db.update(index, updatedData);
    setHistory(updatedHistory);
  };

  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
    const timestamp = new Date().toISOString();
    const solutionWithMeta = { ...solution, timestamp };

    setAnalysisData(prev => {
        if (!prev || prev.timestamp !== analysisId) return prev;

        return {
            ...prev,
            generatedSolutions: {
                ...(prev.generatedSolutions || {}),
                [recommendationId]: solutionWithMeta
            }
        };
    });

    // We need to find the index in the history to update the DB
    setHistory(prevHistory => {
        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
        if (index !== -1) {
            const updatedItem = {
                ...prevHistory[index],
                generatedSolutions: {
                    ...(prevHistory[index].generatedSolutions || {}),
                    [recommendationId]: solutionWithMeta
                }
            };
            // Persist using db service
            const newHistory = [...prevHistory];
            newHistory[index] = updatedItem;
            // Note: calling db.update relies on index which matches prevHistory order if initialized from DB
            db.update(index, updatedItem);
            return newHistory;
        }
        return prevHistory;
    });
  }, []); 

  // Helpers pour ajouter du contenu aux bibliothèques
  const handleAddToSmcLibrary = (item: SMCContent) => setSmcLibrary(prev => [item, ...prev]);
  const handleAddToTruthLibrary = (item: SMCContent) => setTruthLibrary(prev => [item, ...prev]);
  const handleAddToSchemaLibrary = (item: SMCContent) => setSchemaLibrary(prev => [item, ...prev]);
  const handleAddToRobotsLibrary = (item: SMCContent) => setRobotsLibrary(prev => [item, ...prev]);

  const handleNavigateToPublisher = (data: { topic: string, url: string, brief: string }) => {
    setPublisherRequestData(data);
    navigateTo('publisher-request');
  };

  const handleNavigateToDirectory = () => {
    navigateTo('directory');
  };

  const handleDeductCredits = (amount: number): boolean => {
    if (!user) {
        if(confirm("Vous devez être connecté pour effectuer cette action. Se connecter maintenant ?")) {
            navigateTo('login');
        }
        return false;
    }

    if (user.credits < amount) {
        // Redirection explicite vers la section GTO Gas (Recharge)
        alert(`Solde GTO Gas insuffisant pour générer cette solution.\n\nIl vous manque ${amount - user.credits} crédits.\n\nRedirection vers la station de recharge...`);
        navigateTo('recharge');
        return false;
    }

    setUser(prev => prev ? { ...prev, credits: prev.credits - amount } : null);
    return true;
  };

  const handleRecharge = (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => {
    if (!user) return;

    setUser({ 
        ...user, 
        credits: user.credits + amount,
        plan: planLevel 
    });

    // Si c'est une recharge depuis la page de recharge, on ne force pas le retour, l'UX est gérée dans Recharge.tsx
  };

  const handleUpgradePlan = (newPlan: 'free' | 'pro' | 'enterprise') => {
    if (!user) return;
    setUser({ ...user, plan: newPlan });
  };

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    // On réinitialise l'historique pour éviter que le bouton retour ne renvoie au login
    // et on force la navigation vers le dashboard
    setViewHistory(['home']); 
    setCurrentView('analyze'); // Redirection vers Nouvel Audit
    setRefreshKey(prev => prev + 1);
  };

  const handleLogout = () => {
    setIsMobileMenuOpen(false);
    setUser(null);
    setCurrentView('home');
    setViewHistory([]);
    setRefreshKey(prev => prev + 1);
  };

  useEffect(() => {
    if (!user && isMobileMenuOpen) {
      setIsMobileMenuOpen(false);
    }
  }, [user, isMobileMenuOpen]);

  useEffect(() => {
    if (!isMobileMenuOpen) return;
    const previousOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = previousOverflow;
    };
  }, [isMobileMenuOpen]);

  const NavItem = ({ view, label, icon: Icon, onClick, active }: { view?: typeof currentView, label: string, icon: React.ElementType, onClick?: () => void, active?: boolean }) => {
    const handleClick = onClick ? onClick : () => view && navigateTo(view);
    const isActive = active !== undefined ? active : (view && currentView === view);

    return (
      <button
        onClick={handleClick}
        className={`w-full flex items-center gap-3 px-3.5 py-2.5 rounded-xl text-[14px] transition-all duration-200 group font-sans ${
          isActive
            ? 'bg-white/[0.08] text-white font-semibold'
            : 'text-gray-500 hover:text-white hover:bg-white/[0.04] font-medium'
        }`}
      >
        <Icon size={17} className={isActive ? "text-purple-400" : "text-gray-600 group-hover:text-gray-300"} />
        <span>{label}</span>
      </button>
    );
  };

  const PlaceholderView = ({ title, icon: Icon }: { title: string, icon: React.ElementType }) => (
    <div className="flex flex-col items-center justify-center h-[80vh] text-center p-8 animate-in fade-in zoom-in duration-300">
      <div className="w-24 h-24 bg-white/5 rounded-full flex items-center justify-center mb-6 shadow-inner border border-white/10">
        <Icon size={48} className="text-gray-500 opacity-50" />
      </div>
      <h2 className="text-3xl font-serif font-bold text-white mb-4">{title}</h2>
      <p className="text-gray-400 max-w-md mb-8">
        {t.common.featureInDev}
      </p>
      <button
        onClick={() => navigateTo('dashboard')}
        className="px-6 py-3 bg-white/10 hover:bg-white/20 text-white rounded-xl transition-all flex items-center gap-2 font-medium"
      >
        <LayoutDashboard size={18} /> {t.common.returnToDashboard}
      </button>
    </div>
  );

  return (
    <div className="min-h-screen flex flex-col font-sans text-gray-100 selection:bg-primary/30 bg-black">
      {/* NinjaPromo-style Floating Pill Navbar */}
      <nav className="sticky top-0 z-50 px-4 pt-3">
        <div className="max-w-7xl mx-auto bg-[#111111] rounded-full px-6 h-14 flex items-center justify-between border border-white/[0.06] shadow-lg shadow-black/30">
          <div className="flex items-center gap-2.5">
            {user && (
              <button
                type="button"
                onClick={() => setIsMobileMenuOpen(prev => !prev)}
                className="md:hidden w-9 h-9 rounded-full border border-white/[0.08] bg-white/[0.03] text-gray-300 hover:text-white hover:bg-white/[0.06] transition-colors flex items-center justify-center"
                aria-label={isMobileMenuOpen ? "Fermer le menu" : "Ouvrir le menu"}
                aria-expanded={isMobileMenuOpen}
                aria-controls="mobile-sidebar-menu"
              >
                {isMobileMenuOpen ? <X size={17} /> : <Menu size={17} />}
              </button>
            )}
            <div
              className="flex items-center gap-2.5 cursor-pointer"
              onClick={() => navigateTo('home')}
            >
            <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center text-white font-bold font-serif text-base">
              C
            </div>
            <span className="font-sans text-lg font-bold tracking-tight hidden sm:block text-white">CitedBy.ai</span>
            </div>
          </div>

          <div className="flex items-center gap-5">
            {user ? (
              <div className="flex items-center gap-3">
                <LanguageSelector compact />
                <button
                  onClick={() => navigateTo('recharge')}
                  className="hidden md:flex items-center gap-1.5 px-3 py-1 rounded-full hover:bg-white/5 transition-colors group"
                  title="Recharger GTO Gas"
                >
                  <Fuel size={14} className="text-primary fill-primary group-hover:animate-pulse" />
                  <span className="text-sm font-bold text-white group-hover:text-primary">{user.credits}</span>
                </button>
                <div className="h-6 w-px bg-white/10 hidden md:block"></div>
                <div className="flex items-center gap-2.5">
                   <div
                     className="text-right hidden sm:block cursor-pointer"
                     onClick={() => navigateTo('account')}
                   >
                     <p className="text-sm font-medium text-white leading-none hover:text-primary transition-colors">{user.name}</p>
                     <p className="text-[10px] text-gray-500 uppercase tracking-wider mt-0.5">{user.plan.toUpperCase()}</p>
                   </div>
                   <button
                    title="Mon Compte"
                    onClick={() => navigateTo('account')}
                    className="w-8 h-8 rounded-full bg-white/5 border border-white/10 text-white text-sm font-bold flex items-center justify-center hover:border-primary/50 transition-colors"
                   >
                     {user.name.charAt(0).toUpperCase()}
                   </button>
                </div>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <LanguageSelector compact />
                <button
                  onClick={() => navigateTo('login')}
                  className="btn-gradient text-sm !py-2 !px-5"
                >
                  {t.nav.login}
                </button>
              </div>
            )}
          </div>
        </div>
      </nav>

      {user && (
        <>
          <div
            className={`md:hidden fixed inset-0 z-40 bg-black/70 backdrop-blur-sm transition-opacity duration-300 ${
              isMobileMenuOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
            }`}
            onClick={() => setIsMobileMenuOpen(false)}
          />
          <aside
            id="mobile-sidebar-menu"
            className={`md:hidden fixed top-0 left-0 bottom-0 z-50 w-[84%] max-w-[320px] bg-[#111111] border-r border-white/[0.08] shadow-2xl shadow-black/50 transform transition-transform duration-300 ease-out ${
              isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'
            }`}
          >
            <div className="h-full flex flex-col pt-20 pb-6 px-4 overflow-y-auto">
              <div className="bg-black/40 border border-white/[0.06] rounded-2xl p-3 space-y-1">
                <NavItem label={t.nav.home} icon={HomeIcon} view="home" />
                <NavItem label={t.nav.newAudit} icon={ScanLine} view="analyze" />
                <NavItem label={t.nav.dashboard} icon={LayoutDashboard} view="dashboard" />
                <NavItem label={t.nav.monitoringAEO} icon={Wrench} view="projects" active={['projects', 'results'].includes(currentView)} />
                <NavItem label={t.nav.generativeTools} icon={Sparkles} view="generative-tools" active={['generative-tools', 'smc-studio', 'source-of-truth', 'schema-org', 'robots-txt', 'content-writer', 'reputation', 'bot-tracking'].includes(currentView)} />
                <NavItem label={t.nav.indexedDirectory} icon={Globe} view="directory" active={['directory', 'directory-entity'].includes(currentView)} />
                <NavItem label={t.nav.gtoGas} icon={Fuel} view="recharge" />
                <NavItem label={t.nav.affiliation} icon={Share2} view="affiliation" />

                <div className="my-4 border-t border-white/[0.08] mx-4"></div>

                <NavItem label={t.nav.planBilling} icon={CreditCard} view="plan" />
                <NavItem label={t.nav.myAccount} icon={UserIcon} view="account" />
              </div>
            </div>
          </aside>
        </>
      )}

      <div className="flex-grow flex flex-col md:flex-row max-w-7xl mx-auto w-full relative">
        {user && (
          <aside className="hidden md:flex w-64 flex-col pr-4 py-6 sticky top-[4.5rem] h-[calc(100vh-4.5rem)] overflow-y-auto">
            <div className="bg-[#111111] border border-white/[0.06] rounded-2xl p-3 space-y-1 shadow-lg overflow-y-auto custom-scrollbar">

               <NavItem label={t.nav.home} icon={HomeIcon} view="home" />
               <NavItem label={t.nav.newAudit} icon={ScanLine} view="analyze" />
               <NavItem label={t.nav.dashboard} icon={LayoutDashboard} view="dashboard" />
               <NavItem label={t.nav.monitoringAEO} icon={Wrench} view="projects" active={['projects', 'results'].includes(currentView)} />
               <NavItem label={t.nav.generativeTools} icon={Sparkles} view="generative-tools" active={['generative-tools', 'smc-studio', 'source-of-truth', 'schema-org', 'robots-txt', 'content-writer', 'reputation', 'bot-tracking'].includes(currentView)} />
               <NavItem label={t.nav.indexedDirectory} icon={Globe} view="directory" active={['directory', 'directory-entity'].includes(currentView)} />
               <NavItem label={t.nav.gtoGas} icon={Fuel} view="recharge" />
               <NavItem label={t.nav.affiliation} icon={Share2} view="affiliation" />

               <div className="my-4 border-t border-white/10 mx-4"></div>

               <NavItem label={t.nav.planBilling} icon={CreditCard} view="plan" />
               <NavItem label={t.nav.myAccount} icon={UserIcon} view="account" />
            </div>
          </aside>
        )}

        <main className="flex-1 w-full min-w-0 pb-20 md:pb-0">
          <Suspense fallback={<div className="flex items-center justify-center h-[60vh]"><div className="w-8 h-8 border-2 border-purple-500/30 border-t-purple-500 rounded-full animate-spin"></div></div>}>
          {currentView === 'home' && (
            <Home 
                key={`home-${refreshKey}`}
                onNavigate={(view) => navigateTo(view)} 
                user={user} 
                onDirectRecharge={handleDirectRecharge}
            />
          )}

          {currentView === 'login' && (
            <Login key={`login-${refreshKey}`} onLogin={handleLogin} onBack={goBack} />
          )}

          {currentView === 'dashboard' && (
            <Dashboard 
                key={`dashboard-${refreshKey}`}
                onBack={goBack} 
                history={history} 
                onView={handleViewAnalysis}
                onNavigate={navigateTo}
            />
          )}

          {currentView === 'generative-tools' && (
            <GenerativeTools key={`generative-tools-${refreshKey}`} onNavigate={navigateTo} />
          )}

          {currentView === 'analyze' && (
            <Analyze key={`analyze-${refreshKey}`} onAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} />
          )}

          {currentView === 'results' && analysisData && (
            <Results 
              key={`results-${refreshKey}`}
              data={analysisData} 
              onBack={goBack} 
              user={user}
              onDeductCredits={handleDeductCredits}
              onSaveSolution={handleSaveSolution}
              initialTab={resultsTab as any}
              onNewAnalysis={() => navigateTo('analyze')}
            />
          )}

          {currentView === 'history' && (
            <HistoryView
              key={`history-${refreshKey}`}
              onBack={goBack}
              history={history}
              onView={handleViewAnalysis}
            />
          )}

          {currentView === 'smc-studio' && (
            <SMCStudio 
              key={`smc-studio-${refreshKey}`}
              onBack={goBack} 
              user={user}
              onDeductCredits={handleDeductCredits}
              library={smcLibrary}
              onAddToLibrary={handleAddToSmcLibrary}
              onNavigateToPublisher={handleNavigateToPublisher}
              onNavigateToDirectory={handleNavigateToDirectory}
            />
          )}

          {currentView === 'source-of-truth' && (
            <SourceOfTruth 
              key={`source-of-truth-${refreshKey}`}
              onBack={goBack} 
              history={history}
              user={user}
              onDeductCredits={handleDeductCredits}
              savedFiles={truthLibrary}
              onSaveFile={handleAddToTruthLibrary}
            />
          )}

          {currentView === 'schema-org' && (
            <SchemaOrg 
              key={`schema-org-${refreshKey}`}
              onBack={goBack} 
              history={history}
              user={user}
              onDeductCredits={handleDeductCredits}
              savedFiles={schemaLibrary}
              onSaveFile={handleAddToSchemaLibrary}
            />
          )}

          {currentView === 'publisher-request' && (
            <PublisherRequest 
              key={`publisher-request-${refreshKey}`}
              onBack={goBack}
              user={user}
              data={publisherRequestData}
            />
          )}

          {currentView === 'robots-txt' && (
            <RobotsTxt 
              key={`robots-txt-${refreshKey}`}
              onBack={goBack} 
              history={history}
              user={user}
              onDeductCredits={handleDeductCredits}
              onUpdateAnalysis={handleUpdateAnalysis}
              savedFiles={robotsLibrary}
              onSaveFile={handleAddToRobotsLibrary}
            />
          )}

          {currentView === 'directory' && (
            <Directory 
              key={`directory-${refreshKey}`}
              onBack={goBack} 
              onViewEntity={handleViewDirectoryEntity}
              onNavigateToPlan={() => {
                setInitialPlanTab('pricing');
                navigateTo('plan');
              }}
            />
          )}

          {/* Nouvelle vue Directory Entity (Public Profile) */}
          {currentView === 'directory-entity' && analysisData && (
            <DirectoryEntity 
              key={`directory-entity-${refreshKey}`}
              data={analysisData}
              onBack={goBack}
            />
          )}

          {currentView === 'recharge' && (
            <Recharge 
              key={`recharge-${refreshKey}`}
              onBack={goBack} 
              onRecharge={handleRecharge}
              user={user}
              onNavigate={(view) => navigateTo(view as typeof currentView)} 
              initialPackId={initialRechargePackId}
            />
          )}

          {currentView === 'plan' && (
            <Plan 
              key={`plan-${refreshKey}`}
              onBack={goBack} 
              user={user}
              onUpgrade={handleUpgradePlan}
              initialTab={initialPlanTab}
            />
          )}

          {currentView === 'projects' && (
            <Projects 
              key={`projects-${refreshKey}`}
              onBack={goBack} 
              onNavigateToAnalysis={() => navigateTo('analyze')}
              user={user}
              history={history}
              onViewAnalysis={handleViewAnalysis}
              projectCount={monthlyProjectCount}
              maxProjects={user ? PLAN_LIMITS[user.plan] : 1}
              onNavigateToPlan={() => navigateTo('plan')}
              onDeductCredits={handleDeductCredits}
              onSaveSolution={handleSaveSolution}
              onNewAnalysis={() => navigateTo('analyze')}
              onNavigateToRecharge={() => navigateTo('recharge')}
              initialUrl={analysisData?.url}
              initialTab={resultsTab}
            />
          )}

          {currentView === 'account' && (
            <Account 
              key={`account-${refreshKey}`}
              user={user} 
              onLogout={handleLogout}
              onNavigate={navigateTo}
            />
          )}

          {/* Client Database View */}
          {currentView === 'clients' && (
            <Clients 
              key={`clients-${refreshKey}`}
              onBack={goBack}
              onNavigate={(view) => navigateTo(view as typeof currentView)}
            />
          )}

          {/* Affiliation Database View */}
          {currentView === 'affiliation' && (
            <Affiliation
              key={`affiliation-${refreshKey}`}
              onBack={goBack}
              user={user}
            />
          )}

          {/* AI Content Writer B2B */}
          {currentView === 'content-writer' && (
            <ContentWriter
              key={`content-writer-${refreshKey}`}
              onBack={goBack}
              user={user}
              onDeductCredits={handleDeductCredits}
            />
          )}

          {/* Reputation & Sentiment IA */}
          {currentView === 'reputation' && (
            <Reputation
              key={`reputation-${refreshKey}`}
              onBack={goBack}
              user={user}
              onDeductCredits={handleDeductCredits}
            />
          )}

          {/* Bot Tracking - Activation & Suivi des Bots IA */}
          {currentView === 'bot-tracking' && (
            <BotTracking
              key={`bot-tracking-${refreshKey}`}
              onBack={goBack}
              user={user}
            />
          )}

          {/* Messagerie */}
          {currentView === 'messages' && (
            <Messages
              key={`messages-${refreshKey}`}
              onBack={goBack}
              user={user}
            />
          )}
          {currentView === 'alerts' && (
            <AlertsAEO
              key={`alerts-aeo-${refreshKey}`}
              onBack={goBack}
              user={user}
              onNavigate={(view) => navigateTo(view as typeof currentView)}
            />
          )}
          </Suspense>
        </main>
      </div>

      {user && (
        <div className={`md:hidden fixed bottom-0 left-0 right-0 bg-black/90 backdrop-blur-lg border-t border-white/[0.06] z-50 pb-safe transition-opacity duration-200 ${
          isMobileMenuOpen ? 'opacity-0 pointer-events-none' : 'opacity-100'
        }`}>
          <div className="flex justify-around items-center h-16 px-2">
            {[
              { view: 'dashboard', icon: LayoutDashboard, label: t.nav.dash },
              { view: 'projects', icon: FolderOpen, label: t.nav.projects },
              { view: 'analyze', icon: ScanLine, label: t.nav.audit },
              { view: 'account', icon: UserIcon, label: t.nav.account }
            ].map((item) => (
              <button
                key={item.view}
                onClick={() => navigateTo(item.view as any)}
                className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${
                  currentView === item.view ? 'text-primary' : 'text-gray-500'
                }`}
              >
                <item.icon size={20} className={currentView === item.view ? 'fill-primary/20' : ''} />
                <span className="text-[10px] font-medium">{item.label}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      <footer className={`border-t border-white/[0.06] bg-black mt-auto ${user ? 'pb-20 md:pb-0' : ''}`}>
        <div className="max-w-7xl mx-auto px-4 py-16">
          <div className="grid md:grid-cols-4 gap-12 mb-12">
            <div className="space-y-4">
              <div className="flex items-center gap-2">
                <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center text-white font-bold font-serif text-base">
                  C
                </div>
                <span className="font-serif text-xl font-bold tracking-tight text-white">CitedBy.ai</span>
              </div>
              <p className="text-sm text-gray-400 leading-relaxed">
                {t.footer.tagline}
              </p>
            </div>
            <div>
              <h4 className="font-bold text-white mb-6">{t.footer.product}</h4>
              <ul className="space-y-3 text-sm text-gray-400">
                <li><button onClick={() => navigateTo('analyze')} className="hover:text-primary transition-colors text-left">{t.footer.freeAudit}</button></li>
                <li><button onClick={() => navigateTo('directory')} className="hover:text-primary transition-colors text-left">{t.footer.indexDirectory}</button></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.devApi}</a></li>
              </ul>
            </div>
            <div>
              <h4 className="font-bold text-white mb-6">{t.footer.aeoResources}</h4>
              <ul className="space-y-3 text-sm text-gray-400">
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.schemaGuide}</a></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.llmFunctioning}</a></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.aiComparison}</a></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.techBlog}</a></li>
              </ul>
            </div>
            <div>
              <h4 className="font-bold text-white mb-6">{t.footer.company}</h4>
              <ul className="space-y-3 text-sm text-gray-400">
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.about}</a></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.contact}</a></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.legal}</a></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.privacy}</a></li>
              </ul>
            </div>
          </div>
          <div className="border-t border-white/5 pt-8 flex flex-col md:flex-row justify-between items-center text-xs text-gray-500">
            <p>{t.footer.copyright}</p>
            <div className="flex gap-2 items-center mt-4 md:mt-0">
               <span className="w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse"></span>
               {t.common.operationalSystems}
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;
"}

